use std::error::Error;
use std::fmt::{self, Write};

#[derive(Debug)]
struct IoError { 
    message: String
}
impl fmt::Display for IoError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "I/O Failure: {}", self.message)
    }
}
impl Error for IoError {}

type Result<T> = std::result::Result<T, Box<dyn Error + Send + Sync>>;

struct Peripheral<const ID: usize> {
    base_address: u32,
}

impl<const ID: usize> Peripheral<ID> {
    fn new(base_addr: u32) -> Self {
        Peripheral { base_address: base_addr }
    }

    fn write_register(&self, offset: u32, value: u32) -> Result<()> {
        println!("Writing 0x{:X} to peripheral {} at address 0x{:X}", value, ID, self.base_address + offset);
        Ok(())
    }
}

struct Bootloader {
    gpio: Peripheral<10>,
    uart: Peripheral<20>,
}

impl Bootloader {
    fn new() -> Self {
        Bootloader {
            gpio: Peripheral::new(0x4000_0000),
            uart: Peripheral::new(0x4001_0000),
        }
    }

    fn initialize(&self) -> Result<()> {
        println!("Initializing hardware peripherals...");
        let _ = self.gpio.write_register(0x00, 0xAAAA)?; 
        self.uart.write_register(0x04, 1)?; 
        Ok(()) 
    }
}

fn main() -> Result<()> {
    let bl = Bootloader::new();
    bl.initialize()?;
    println!("Bootloader setup complete.");
    Ok(())
}

use std::collections::HashMap;
use rand::Rng;

#[derive(Debug)]
struct MixedRecord {
    id: u64,
    integer_feature: i32,
    float_measurement: f64,
}

fn process_records(data: Vec<MixedRecord>) -> HashMap<i32, Vec<(f64, u64)>> {
    let mut grouping_map: HashMap<i32, Vec<(f64, u64)>> = HashMap::new();

    for record in data {
        let key = record.integer_feature;
        let value = (record.float_measurement, record.id);
        grouping_map.entry(key).or_default().push(value);
    }
    grouping_map
}

fn main() {
    let mut rng = rand::thread_rng();
    const DATA_SIZE: usize = 100;

    let data: Vec<MixedRecord> = (0..DATA_SIZE)
        .map(|_| MixedRecord {
            id: rng.gen::<u64>(),
            integer_feature: (rng.gen_range(-100..=100) % 101) as i32,
            float_measurement: rng.gen_range(0.0..=1000.0),
        })
        .collect();

    let result = process_records(data);

    for (key, records) in result {
        println!("Group Key: {}
Records Found: {}
", key, records.len());
    }
}

use std::collections::HashMap;

struct UserRecord {
    user_id: u32,
    username: String,
    is_active: bool,
}

fn filter_inactive_users(all_records: &Vec<UserRecord>) -> Vec<&UserRecord> {
    let mut active_users = Vec::new();
    for record in all_records.iter() {
        if record.is_active {
            active_users.push(record);
        }
    }
    active_users
}

fn main() {
    let raw_data = vec![
        UserRecord { user_id: 101, username: "alice".to_string(), is_active: true },
        UserRecord { user_id: 202, username: "bob".to_string(), is_active: false },
        UserRecord { user_id: 303, username: "charlie".to_string(), is_active: true },
        UserRecord { user_id: 404, username: "diana".to_string(), is_active: false },
    ];

    let visible_users = filter_inactive_users(&raw_data);

    println!("Found {} active users for the client view.", visible_users.len());
    for user in visible_users {
        println!("- ID: {}, Username: {}", user.user_id, user.username);
    }
}

use std::collections::HashMap;

struct DataLoader {
    data_map: HashMap<u32, String>,
}
impl DataLoader {
    fn new() -> Self {
        DataLoader {
            data_map: HashMap::new()
        }
    }

    fn set_batch(&mut self, keys: &[u32], values: &[String]) {
        for (i, &key) in keys.iter().enumerate() {
            let value = &values[i];
            self.data_map.insert(key, value.clone());
        }
    }

    fn load(&self, key: u32) -> Option<String> {
        self.data_map.get(&key).cloned()
    }
}

fn main() {
    let mut loader = DataLoader::new();

    let keys_to_batch = vec![101, 102, 103];
    let corresponding_values = vec!["User A Data".to_string(), "Product B Details".to_string(), "Order C Info".to_string()];

    loader.set_batch(&keys_to_batch, &corresponding_values);

    let key_one = 102;
    if let Some(data) = loader.load(key_one) {
        println!("Successfully loaded data for ID {}: {}", key_one, data);
    }

    let missing_key = 999;
    match loader.load(missing_key) {
        Some(data) => println!("Unexpectedly found data for ID {}: {}", missing_key, data),
        None => println!("Correctly handled missing key: {}", missing_key),
    }
}

use std::collections::HashMap;

struct Record {
    id: u64,
    data_type: String,
    payload: Vec<f32>,
}

fn process_record(record: &Record) -> Result<Vec<f32>, String> {
    if record.data_type == "embedding" {
        Ok(record.payload.clone())
    } else if record.data_type == "metadata" {
        let mut result = vec![0.0; 1];
        result[0] = record.payload.get(0).copied().unwrap_or(0.0);
        Ok(result)
    } else {
        Err(format!("Unknown data type encountered: {}", record.data_type))
    }
}

fn main() {
    let records = vec![ 
        Record { id: 1, data_type: "embedding".to_string(), payload: vec![0.1, 0.2] },
        Record { id: 2, data_type: "metadata".to_string(), payload: vec![5.0] },
        Record { id: 3, data_type: "embedding".to_string(), payload: vec![-1.0, -2.0] },
    ];

    let mut processed_results: HashMap<u64, Result<Vec<f32>, String>> = HashMap::new();

    for record in records {
        match process_record(&record) {
            Ok(result) => {
                processed_results.insert(record.id, Ok(result));
            }
            Err(e) => {
                processed_results.insert(record.id, Err(e));
            }
        }
    }

    for (id, result) in processed_results {
        match result { 
            Ok(data) => println!("Successfully processed record ID {}: Result vector length {}", id, data.len()),
            Err(e) => println!("Failed to process record ID {}: Error {}", id, e),
        }
    }
}
